import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

/** One managed setting with a masked effective value (`GET /api/admin/settings`). */
export interface SettingView {
  key: string;
  label: string;
  service: string;
  configured: boolean;
  /** Masked effective value, e.g. `post••••/app`, or null when unset. */
  value: string | null;
  source: 'env' | 'db' | null;
  updatedAt: string | null;
}

/** Payload for `PATCH /api/admin/settings`. */
export interface SettingUpdate {
  key: string;
  value: string;
}

/**
 * Admin settings client. Lists managed service/integration keys with masked
 * values and upserts overrides.
 */
@Injectable({ providedIn: 'root' })
export class SettingsApiService {
  private readonly http = inject(HttpClient);

  list(): Observable<SettingView[]> {
    return this.http.get<SettingView[]>('/api/admin/settings');
  }

  update(updates: SettingUpdate[]): Observable<{ updated: number }> {
    return this.http.patch<{ updated: number }>('/api/admin/settings', updates);
  }
}
