import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ServiceConfig } from '../core/models';
import {
  SettingsApiService,
  SettingView,
} from '../core/settings-api.service';

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [FormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrl: './admin-settings.component.css',
})
export class AdminSettingsComponent implements OnInit {
  private readonly api = inject(SettingsApiService);

  /** One card per managed setting, masked value shown as the field placeholder. */
  readonly services = signal<ServiceConfig[]>([]);

  /** Per-service transient "saved" confirmation. */
  readonly savedKey = signal<string | null>(null);

  ngOnInit(): void {
    this.reload();
  }

  private reload(): void {
    this.api.list().subscribe({
      next: (settings) => this.services.set(settings.map((s) => this.toCard(s))),
      error: () => this.services.set([]),
    });
  }

  /** Map a masked SettingView onto the credential-card view model. */
  private toCard(s: SettingView): ServiceConfig {
    return {
      key: s.key,
      label: s.label,
      description: s.configured
        ? `${s.service} · current value ${s.value ?? '••••'}`
        : `${s.service} · no value configured yet`,
      configured: s.configured,
      fields: [
        {
          key: s.key,
          label: 'Value',
          type: 'password',
          placeholder: s.value ?? 'Not set',
          value: '',
        },
      ],
    };
  }

  updateField(serviceKey: string, fieldKey: string, value: string): void {
    this.services.update((list) =>
      list.map((s) =>
        s.key !== serviceKey
          ? s
          : {
              ...s,
              fields: s.fields.map((f) =>
                f.key === fieldKey ? { ...f, value } : f,
              ),
            },
      ),
    );
  }

  save(serviceKey: string): void {
    const svc = this.services().find((s) => s.key === serviceKey);
    const value = svc?.fields[0]?.value.trim() ?? '';
    if (!value) {
      return; // nothing new to upsert
    }
    this.api.update([{ key: serviceKey, value }]).subscribe({
      next: () => {
        this.savedKey.set(serviceKey);
        this.reload();
      },
      error: () => this.savedKey.set(null),
    });
  }
}
